  describe('state invariants (stateful PBT)', () => {
    it('always: recorded generations have non-empty source and concept', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('generate'), input: fc.record({ manifest: fc.string({ minLength: 1, maxLength: 50 }), source: fc.string({ minLength: 1, maxLength: 50 }), concept: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('generateAll'), input: fc.record({ manifest: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('preview'), input: fc.record({ manifest: fc.string({ minLength: 1, maxLength: 50 }), source: fc.string({ minLength: 1, maxLength: 50 }), concept: fc.string({ minLength: 1, maxLength: 50 }), action: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('list'), input: fc.record({  }) }),
              fc.record({ action: fc.constant('register'), input: fc.record({  }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = externalHandlerGenHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(externalHandlerGenHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

    it('never: generation recorded with empty handler code', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('generate'), input: fc.record({ manifest: fc.string({ minLength: 1, maxLength: 50 }), source: fc.string({ minLength: 1, maxLength: 50 }), concept: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('generateAll'), input: fc.record({ manifest: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('preview'), input: fc.record({ manifest: fc.string({ minLength: 1, maxLength: 50 }), source: fc.string({ minLength: 1, maxLength: 50 }), concept: fc.string({ minLength: 1, maxLength: 50 }), action: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('list'), input: fc.record({  }) }),
              fc.record({ action: fc.constant('register'), input: fc.record({  }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = externalHandlerGenHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(externalHandlerGenHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
                // Never: generation recorded with empty handler code
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

  });

